73: // ─── Ollama Integration ──────────────────────────────────────────────────────
74: 
75: async function callOllama(agent, messages, stream, res) {
76:   const baseUrl = agent.ollamaBase || 'http://localhost:11434';
77:   const modelName = (agent.model || 'ollama/llama3').replace('ollama/', '');
78:   
79:   const payload = JSON.stringify({
80:     model: modelName,
81:     messages: messages,
82:     stream: stream,
83:     options: {
84:       temperature: agent.temperature ?? 0.7,
85:       num_predict: agent.maxTokens ?? 4096
86:     }
87:   });
88: 
89:   return new Promise((resolve, reject) => {
90:     const url = new URL(`${baseUrl}/api/chat`);
91:     const options = {
92:       hostname: url.hostname,
93:       port: url.port || 11434,
94:       path: url.pathname,
95:       method: 'POST',
96:       headers: {
97:         'Content-Type': 'application/json',
98:         'Content-Length': Buffer.byteLength(payload)
99:       }
100:     };
101: 
102:     const req = http.request(options, (ollamaRes) => {
103:       if (stream) {
104:         // Stream SSE to client
105:         let buffer = '';
106:         ollamaRes.on('data', chunk => {
107:           buffer += chunk.toString();
108:           const lines = buffer.split('\n');
109:           buffer = lines.pop();
110:           lines.forEach(line => {
111:             if (!line.trim()) return;
112:             try {
113:               const parsed = JSON.parse(line);
114:               if (parsed.message?.content) {
115:                 res.write(`data: ${JSON.stringify({ delta: parsed.message.content, done: false })}\n\n`);
116:               }
117:               if (parsed.done) {
118:                 res.write(`data: ${JSON.stringify({ delta: '', done: true })}\n\n`);
119:                 res.end();
120:                 resolve({ streaming: true });
121:               }
122:             } catch (_) {}
123:           });
124:         });
125:         ollamaRes.on('error', reject);
126:       } else {
127:         let data = '';
128:         ollamaRes.on('data', chunk => data += chunk.toString());
129:         ollamaRes.on('end', () => {
130:           try {
131:             const parsed = JSON.parse(data);
132:             resolve({ content: parsed.message?.content || '', done: true });
133:           } catch (e) {
134:             reject(new Error('Failed to parse Ollama response'));
135:           }
136:         });
137:       }
138:     });
139: 
140:     req.on('error', reject);
141:     req.setTimeout(settings.protocols?.timeoutMs || 120000, () => {
142:       req.destroy(new Error('Ollama request timeout'));
143:     });
144:     req.write(payload);
145:     req.end();
146:   });
147: }
148: 
149: async function callAgent(agent, messages, stream, res) {
150:   try {
151:     return await callOllama(agent, messages, stream, res);
152:   } catch (err) {
153:     // Fallback mock response when Ollama is not available
154:     console.warn(`[Agent] Ollama unavailable for agent "${agent.id}": ${err.message}`);
155:     const mockContent = `[MOCK RESPONSE — Ollama not connected]\n\nAgent **${agent.name}** received your message. To enable real AI responses, make sure Ollama is running at \`${agent.ollamaBase}\` with model \`${agent.model.replace('ollama/', '')}\` loaded.\n\nStart with:\n\`\`\`\nollama serve\nollama pull ${agent.model.replace('ollama/', '')}\n\`\`\``;
156:     if (stream) {
157:       res.write(`data: ${JSON.stringify({ delta: mockContent, done: false })}\n\n`);
158:       res.write(`data: ${JSON.stringify({ delta: '', done: true })}\n\n`);
159:       res.end();
160:       return { streaming: true };
161:     }
162:     return { content: mockContent, done: true };
163:   }
164: }
